solution_code:
import math

class ContextWindowManager:
    def __init__(self, max_tokens: int):
        if max_tokens < 1:
            raise ValueError('max_tokens must be >= 1')
        self.max_tokens = max_tokens

    def count_tokens(self, text: str) -> int:
        return math.ceil(len(text.split()) * 1.3)

    def fits(self, text: str) -> bool:
        return self.count_tokens(text) <= self.max_tokens

    def truncate(self, text: str, strategy: str = 'tail') -> str:
        if self.fits(text):
            return text
        words = text.split()
        # Max words that fit: max_tokens / 1.3
        max_words = int(self.max_tokens / 1.3)
        if strategy == 'tail':
            return ' '.join(words[-max_words:])
        elif strategy == 'head':
            return ' '.join(words[:max_words])
        elif strategy == 'middle_out':
            head_count = max(1, int(max_words * 0.2))
            tail_count = max_words - head_count
            return ' '.join(words[:head_count] + words[-tail_count:])
        else:
            raise ValueError(f"Unknown strategy: {strategy!r}")

    def available_tokens(self, used: int) -> int:
        return self.max_tokens - used

